 1	import { ComponentType, FC } from 'react';
 2	
 3	import { I18nNamespace } from '@config/config';
 4	import { Bullseye, EmptyState, EmptyStateBody, EmptyStateIcon, EmptyStateVariant, Title } from '@patternfly/react-core';
 5	import { useTranslation } from 'react-i18next';
 6	
 7	interface EmptyDataProps {
 8	  message?: string;
 9	  description?: string;
10	  icon?: ComponentType;
11	}
12	
13	const EmptyData: FC<EmptyDataProps> = function ({ message, description, icon }) {
14	  const { t } = useTranslation(I18nNamespace);
15	
16	  return (
17	    <Bullseye>
18	      <EmptyState variant={EmptyStateVariant.lg} isFullHeight data-testid="sk-emptydata">
19	        {icon && <EmptyStateIcon icon={icon} />}
20	        <Title headingLevel="h2" size="lg">
21	          {message || t('Data not found')}
22	        </Title>
23	        {description && <EmptyStateBody>{description}</EmptyStateBody>}
24	      </EmptyState>
25	    </Bullseye>
26	  );
27	};
28	
29	export default EmptyData;

